import { defaultRoomOptions } from '../data/roomsCatalog';
import { defaultDiningCategories, defaultFeaturedPlates, createFoodCheckoutItem } from '../data/diningMenu';
import { buildApiUrl } from './api';

const ROOMS_KEY = 'admin_rooms_catalog';
const DINING_KEY = 'admin_dining_catalog';
const ROOMS_URL = buildApiUrl('/admin/rooms');
const DINING_URL = buildApiUrl('/admin/dining');

const clone = (value) => JSON.parse(JSON.stringify(value));

export const getManagedRooms = () => {
  try {
    const rawValue = localStorage.getItem(ROOMS_KEY);
    return rawValue ? JSON.parse(rawValue) : clone(defaultRoomOptions);
  } catch (error) {
    return clone(defaultRoomOptions);
  }
};

export const cacheManagedRooms = (rooms) => {
  localStorage.setItem(ROOMS_KEY, JSON.stringify(rooms));
};

export const fetchManagedRooms = async () => {
  const response = await fetch(ROOMS_URL, {
    credentials: 'include',
  });
  const data = await response.json();
  if (!response.ok) {
    throw new Error(data.message || 'Unable to load rooms.');
  }
  const rooms = data.rooms?.length ? data.rooms : clone(defaultRoomOptions);
  cacheManagedRooms(rooms);
  return rooms;
};

export const saveManagedRooms = async (rooms) => {
  const response = await fetch(ROOMS_URL, {
    method: 'PUT',
    credentials: 'include',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ rooms }),
  });
  const data = await response.json();
  if (!response.ok) {
    throw new Error(data.message || 'Unable to save rooms.');
  }
  cacheManagedRooms(data.rooms || rooms);
  return data.rooms || rooms;
};

export const getManagedDiningCatalog = () => {
  try {
    const rawValue = localStorage.getItem(DINING_KEY);
    return rawValue
      ? JSON.parse(rawValue)
      : {
          categories: clone(defaultDiningCategories),
          featuredPlates: clone(defaultFeaturedPlates),
        };
  } catch (error) {
    return {
      categories: clone(defaultDiningCategories),
      featuredPlates: clone(defaultFeaturedPlates),
    };
  }
};

export const cacheManagedDiningCatalog = (catalog) => {
  localStorage.setItem(DINING_KEY, JSON.stringify(catalog));
};

export const fetchManagedDiningCatalog = async () => {
  const response = await fetch(DINING_URL, {
    credentials: 'include',
  });
  const data = await response.json();
  if (!response.ok) {
    throw new Error(data.message || 'Unable to load dining catalog.');
  }
  const catalog =
    data.categories?.length || data.featuredPlates?.length
      ? {
          categories: data.categories || [],
          featuredPlates: data.featuredPlates || [],
        }
      : {
          categories: clone(defaultDiningCategories),
          featuredPlates: clone(defaultFeaturedPlates),
        };

  cacheManagedDiningCatalog(catalog);
  return catalog;
};

export const saveManagedDiningCatalog = async (catalog) => {
  const response = await fetch(DINING_URL, {
    method: 'PUT',
    credentials: 'include',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(catalog),
  });
  const data = await response.json();
  if (!response.ok) {
    throw new Error(data.message || 'Unable to save dining catalog.');
  }
  const savedCatalog = {
    categories: data.categories || catalog.categories,
    featuredPlates: data.featuredPlates || catalog.featuredPlates,
  };
  cacheManagedDiningCatalog(savedCatalog);
  return savedCatalog;
};

export const getManagedFoodCheckoutItems = () => {
  const { categories, featuredPlates } = getManagedDiningCatalog();

  return [
    ...featuredPlates.map((plate) =>
      createFoodCheckoutItem({
        title: plate.title,
        description: plate.description,
        image: plate.image,
        price: plate.price,
        type: 'Featured Dish',
        category: plate.tag,
      })
    ),
    ...categories.flatMap((category) =>
      category.items.map((item) =>
        createFoodCheckoutItem({
          title: item.name,
          description: `${category.title} selection`,
          image: item.image,
          price: item.price,
          type: 'Food Order',
          category: category.title,
        })
      )
    ),
  ];
};
